from typing import Optional

def closestValue(root: Optional[object], target: float) -> int:
    closest = root.val
    node = root
    while node is not None:
        if abs(node.val - target) < abs(closest - target):
            closest = node.val
        if target < node.val:
            node = node.left
        else:
            node = node.right
    return closest

